class Solution {
public:
    int flipBits(int n, int k) {
        int res = 0;
        while (k > 0) {
            if ((n & 1) == 0) {
                res += 1;
            } else {
                n >>= 1;
            }
            k--;
        }
        while ((n & 1) == 0) {
            n >>= 1;
        }
        if (k > 0) {
            return 0;
        }
        return n % 1000000007;
    }
};
